// Extract and validate incoming chat message
const body = $input.first().json.body;

const message = body.message || '';
const sessionId = body.sessionId || 'unknown';
const history = body.history || [];

if (!message.trim()) {
  return [{ json: { error: true, answer: 'Please type a question and I\'ll help you out.' } }];
}

// Build conversation context from recent history (last 6 exchanges)
const recentHistory = history.slice(-6);
let conversationContext = '';
if (recentHistory.length > 1) {
  conversationContext = recentHistory
    .slice(0, -1)
    .map(m => `${m.role === 'user' ? 'User' : 'Assistant'}: ${m.content}`)
    .join('\n');
}

return [{ 
  json: { 
    message, 
    sessionId, 
    conversationContext,
    hasError: false
  } 
}];

// Extract answer and source citations from Gemini File Search response
const response = $input.first().json;

let answer = '';
let sourceUrl = null;
let sourceTitle = null;

try {
  const candidates = response.candidates || [];

  if (candidates.length > 0 && candidates[0].content) {
    const parts = candidates[0].content.parts || [];
    answer = parts.map(p => p.text || '').join('');
  }

  // Extract grounding/citation metadata if available
  const groundingMetadata = candidates[0]?.groundingMetadata || {};
  const groundingChunks = groundingMetadata?.groundingChunks || [];
  const supportChunks = groundingMetadata?.groundingSupports || [];

  // Try to get source from grounding metadata
  if (groundingChunks.length > 0) {
    const firstChunk = groundingChunks[0];
    if (firstChunk.retrievedContext) {
      sourceUrl = firstChunk.retrievedContext.uri || null;
      sourceTitle = firstChunk.retrievedContext.title || 'Support Article';
    }
  }

  // Also check for web/retrievalMetadata style citations
  const retrievalMetadata = candidates[0]?.citationMetadata?.citationSources || [];
  if (!sourceUrl && retrievalMetadata.length > 0) {
    sourceUrl = retrievalMetadata[0].uri || null;
  }

} catch (e) {
  // Log error for debugging
  console.error('Response parsing error:', e.message);
}

// Fallback if no answer extracted
if (!answer) {
  answer = "I'm having trouble processing that right now. Please try rephrasing your question, or email us at info@nilsdigital.com for help.";
}

// Clean any GoHighLevel references that might leak through from source docs
answer = answer
  .replace(/GoHighLevel/gi, 'Nils Platform')
  .replace(/\bGHL\b/g, 'Nils Platform')
  .replace(/HighLevel/gi, 'Nils Platform')
  .replace(/LeadConnector/gi, 'Nils Platform');

// Rewrite citation URLs to branded domain
if (sourceUrl) {
  sourceUrl = sourceUrl.replace('help.leadconnectorhq.com', 'help.nilsdigital.com');
}
if (sourceTitle) {
  sourceTitle = sourceTitle
    .replace(/GoHighLevel/gi, 'Nils Platform')
    .replace(/LeadConnector/gi, 'Nils Platform')
    .replace(/HighLevel/gi, 'Nils Platform');
}

return [{
  json: {
    answer,
    sourceUrl,
    sourceTitle
  }
}];

